defmodule TodoList.Domain.Task.Types.TaskId do
  @moduledoc """
  Value object representing a unique task identifier.

  Wraps a UUID string. Once constructed, the TaskId is trusted
  throughout the domain -- validation happens only at creation time.
  """

  @enforce_keys [:value]
  defstruct [:value]

  @type t :: %__MODULE__{value: String.t()}

  @doc """
  Generates a new TaskId with a random UUID.
  """
  @spec new() :: t()
  def new do
    %__MODULE__{value: generate_uuid()}
  end

  @doc """
  Wraps an existing UUID string as a TaskId.

  Raises `ArgumentError` if the string is not a valid UUID.
  """
  @spec new!(String.t()) :: t()
  def new!(uuid_string) when is_binary(uuid_string) do
    raise "not implemented"
  end

  defp generate_uuid do
    raise "not implemented"
  end
end

defmodule TodoList.Domain.Task.Types.Description do
  @moduledoc """
  Value object representing a task description.

  Wraps a non-empty, non-whitespace-only string. Invalid input is
  rejected at construction time ("parse, don't validate").
  """

  @enforce_keys [:value]
  defstruct [:value]

  @type t :: %__MODULE__{value: String.t()}

  @doc """
  Creates a new Description from the given string.

  Raises `ArgumentError` if the string is empty or contains only whitespace.
  """
  @spec new!(String.t()) :: t()
  def new!(text) when is_binary(text) do
    trimmed = String.trim(text)

    if trimmed == "" do
      raise ArgumentError, "description cannot be empty or whitespace-only"
    end

    %__MODULE__{value: trimmed}
  end
end

defmodule TodoList.Domain.Task.Types.Position do
  @moduledoc """
  Value object representing a task's position in the list.

  Wraps a positive integer. Position 1 is the top of the list.
  """

  @enforce_keys [:value]
  defstruct [:value]

  @type t :: %__MODULE__{value: pos_integer()}

  @doc """
  Creates a new Position from the given integer.

  Raises `ArgumentError` if the integer is not positive.
  """
  @spec new!(pos_integer()) :: t()
  def new!(position) when is_integer(position) and position > 0 do
    %__MODULE__{value: position}
  end

  def new!(position) when is_integer(position) do
    raise ArgumentError, "position must be a positive integer, got: #{position}"
  end
end

defmodule TodoList.Domain.Task.Commands.AddTask do
  @moduledoc """
  Command to add a new task to the list.

  The task will be assigned a generated TaskId and placed at
  the next available position by the aggregate.
  """

  alias TodoList.Domain.Task.Types.Description

  @enforce_keys [:description]
  defstruct [:description]

  @type t :: %__MODULE__{description: Description.t()}
end

defmodule TodoList.Domain.Task.Events.TaskAdded do
  @moduledoc """
  Event recording that a new task was added to the list.
  """

  alias TodoList.Domain.Task.Types.{TaskId, Description, Position}

  @enforce_keys [:task_id, :description, :position]
  defstruct [:task_id, :description, :position]

  @type t :: %__MODULE__{
          task_id: TaskId.t(),
          description: Description.t(),
          position: Position.t()
        }
end

defmodule TodoList.Domain.Effects.PublishEvent do
  @moduledoc """
  Effect instructing the imperative shell to append an event
  to the event store.

  The domain returns this struct; the shell pattern-matches on it
  and executes the corresponding IO.
  """

  @enforce_keys [:event]
  defstruct [:event]

  @type t :: %__MODULE__{event: struct()}
end

defmodule TodoList.Domain.Task.Aggregate do
  @moduledoc """
  Pure aggregate for the Task domain.

  Accepts commands and returns effects containing events, or errors.
  State is rebuilt by folding events through `apply/2`.

  This module is part of the functional core -- it performs no IO.
  """

  defstruct next_position: 1, exists: false

  @type t :: %__MODULE__{
          next_position: pos_integer(),
          exists: boolean()
        }

  @doc """
  Returns a new, empty aggregate state.
  """
  @spec new() :: t()
  def new do
    %__MODULE__{}
  end

  @doc """
  Executes a command against the current aggregate state.

  Returns `{:ok, effect}` with a `PublishEvent` effect on success,
  or `{:error, reason}` on failure.
  """
  @spec execute(t(), struct()) :: {:ok, struct()} | {:error, term()}
  def execute(_state, _command) do
    raise "not implemented"
  end

  @doc """
  Applies an event to the aggregate state, returning updated state.

  Used to rebuild state from the event stream.
  """
  @spec apply(t(), struct()) :: t()
  def apply(_state, _event) do
    raise "not implemented"
  end
end

